### 6\. Add argc test commands to [Argcfile.sh](<http://Argcfile.sh>)

Add after the `plugin::update` function:

```bash
# @cmd run bats tests
# @option --filter <FILTER> filter tests by name pattern
# @option --dir <DIR> test directory to run [default: tests]
test() {
    local test_dir="${argc_dir:-tests}"
    local bats_args=()

    if [[ -n "${argc_filter:-}" ]]; then
        bats_args+=(--filter "$argc_filter")
    fi

    cd "$CLAUDE_MARKETPLACE_PATH"

    local test_files=()
    while IFS= read -r -d '' f; do
        test_files+=("$f")
    done < <(find "$test_dir" -name '*.bats' -print0 | sort -z)

    if [[ ${#test_files[@]} -eq 0 ]]; then
        echo "no test files found in $test_dir"
        exit 1
    fi

    bats "${bats_args[@]}" "${test_files[@]}"
}

# @cmd run only hook tests
test::hooks() {
    cd "$CLAUDE_MARKETPLACE_PATH"
    bats tests/hooks/*.bats
}
```

