    base=$(jq -n \
        --arg sid "test-session-$(date +%s)" \
        --arg tp "/tmp/test-transcript.jsonl" \
        --arg cwd "$PWD" \
        '{
            session_id: $sid,
            transcript_path: $tp,
            cwd: $cwd,
            permission_mode: "default"
        }')
    echo "$base" | jq ". * $overrides"
}

# run a hook script with JSON piped to stdin
# captures stdout in $output, stderr in $stderr_output, exit code in $status
run_hook() {
    local hook_script="$1"
    local input_json="${2:-{}}"
    local stderr_file
    stderr_file=$(mktemp)

    set +e
    output=$(echo "$input_json" | bash "$hook_script" 2>"$stderr_file")
    status=$?
    set -e

    stderr_output=$(cat "$stderr_file")
    rm -f "$stderr_file"
}

# assert exact exit code
assert_exit_code() {
    local expected="$1"
    if [[ "$status" -ne "$expected" ]]; then
        echo "Expected exit code $expected, got $status"
        echo "stdout: $output"
        echo "stderr: $stderr_output"
        return 1
    fi
}

# assert a JSON field in $output equals a value
assert_json_field() {
    local path="$1"
    local expected="$2"
    local actual
    actual=$(echo "$output" | jq -r "$path" 2>/dev/null)
    if [[ "$actual" != "$expected" ]]; then
        echo "JSON field $path: expected '$expected', got '$actual'"
        echo "Full output: $output"
        return 1
    fi
}

# assert a JSON field exists and is not null
assert_json_has_field() {
    local path="$1"
    local val
    val=$(echo "$output" | jq -r "$path // \"__null__\"" 2>/dev/null)
    if [[ "$val" == "__null__" || -z "$val" ]]; then
        echo "JSON field $path is missing or null"
        echo "Full output: $output"
        return 1
    fi
}

# assert $output is valid JSON
assert_valid_json() {
    if ! echo "$output" | jq . >/dev/null 2>&1; then
        echo "Output is not valid JSON"
        echo "Output: $output"
        return 1
    fi
}

# assert stderr contains a string
assert_stderr_contains() {
    local expected="$1"
    if [[ "$stderr_output" != *"$expected"* ]]; then
        echo "stderr does not contain: $expected"
        echo "stderr: $stderr_output"
        return 1
    fi
}

# assert stderr does not contain a string
assert_stderr_not_contains() {
    local unexpected="$1"
    if [[ "$stderr_output" == *"$unexpected"* ]]; then
        echo "stderr unexpectedly contains: $unexpected"
        echo "stderr: $stderr_output"
        return 1
    fi
